import{_ as t,o as s,c as o,a0 as n}from"./chunks/framework.BWpMpcZ2.js";const p=JSON.parse('{"title":"Context Settings","description":"","frontmatter":{},"headers":[],"relativePath":"configuration/context.md","filePath":"configuration/context.md"}'),a={name:"configuration/context.md"};function r(i,e,l,c,d,u){return s(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="context-settings" tabindex="-1">Context Settings <a class="header-anchor" href="#context-settings" aria-label="Permalink to &quot;Context Settings&quot;">​</a></h1><p>Context settings control what information the AI receives about your project. This is the most important section -- getting context right is the key to useful AI assistance.</p><h2 id="session-memory" tabindex="-1">Session Memory <a class="header-anchor" href="#session-memory" aria-label="Permalink to &quot;Session Memory&quot;">​</a></h2><p>margin remembers your recent conversation turns (questions and AI responses) to keep the discussion coherent.</p><ul><li><strong>Max History Depth</strong>: Set between 1 and 10 turns. A higher number gives the AI more context but uses more tokens. The default of 5 works well for most conversations.</li></ul><h2 id="tone-preset" tabindex="-1">Tone Preset <a class="header-anchor" href="#tone-preset" aria-label="Permalink to &quot;Tone Preset&quot;">​</a></h2><p>A <strong>tone preset</strong> tells the writer agent what style to use when generating text. These presets are defined as markdown files in your workspace&#39;s <code>styles/</code> folder.</p><ul><li><strong>None</strong>: No style injected. The AI writes in its default voice.</li><li><strong>Auto</strong>: The Planner agent decides which tone fits best based on your request and available styles.</li><li><strong>Specific preset</strong>: Choose from your workspace&#39;s available styles (e.g., &quot;Cinematic&quot;, &quot;General&quot;, &quot;Superman&quot;).</li></ul><p>The sample workspace comes with a few presets to get you started.</p><div class="tip custom-block"><p class="custom-block-title">You can create your own tone presets. See the <a href="./../writing-guide.html#style-presets-tone-presets">Writing Guide</a> for how to define them.</p></div><h2 id="include-document-structure" tabindex="-1">Include Document Structure <a class="header-anchor" href="#include-document-structure" aria-label="Permalink to &quot;Include Document Structure&quot;">​</a></h2><p>When enabled, the AI receives a structural outline (paragraph previews) of your active document. This helps the Planner understand the broader story flow, but consumes more tokens.</p><div class="warning custom-block"><p class="custom-block-title">Consider turning this off if you&#39;re using a smaller local model. The outline can consume a significant portion of your context window.</p></div><h2 id="additional-context" tabindex="-1">Additional Context <a class="header-anchor" href="#additional-context" aria-label="Permalink to &quot;Additional Context&quot;">​</a></h2><p>Write any extra instructions that should be prepended to every AI request. This is useful for persistent preferences:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Always use British spelling.</span></span>
<span class="line"><span>Avoid passive voice.</span></span>
<span class="line"><span>Keep paragraphs under 4 sentences.</span></span></code></pre></div><p>These instructions are added automatically to every interaction with the writer agent.</p><h2 id="reference-files" tabindex="-1">Reference Files <a class="header-anchor" href="#reference-files" aria-label="Permalink to &quot;Reference Files&quot;">​</a></h2><p>The <strong>Reference Files</strong> panel lets you control which files in your workspace the AI can read. Each file has three states:</p><table tabindex="0"><thead><tr><th>State</th><th>Icon</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Available</strong> (default)</td><td>Eye icon</td><td>The Planner can read this file if it decides the content is relevant.</td></tr><tr><td><strong>Pinned</strong></td><td>Pin icon</td><td>This file is always included in every AI request. Good for style guides or world-building rules.</td></tr><tr><td><strong>Blocked</strong></td><td>Eye + strikethrough</td><td>The AI is prevented from reading this file. Useful when smaller models struggle with too much context.</td></tr></tbody></table><p>Click a file&#39;s icon to cycle through the states.</p>`,21)])])}const g=t(a,[["render",r]]);export{p as __pageData,g as default};
